blocks.body:
{
    "level": "B2",
    "intro": "W tym temacie dowiesz się, <strong>gdzie odpowiednia jest strona bierna</strong>, a gdzie lepiej zastosować stan aktywny. Rozważymy także <strong>najczęstsze błędy</strong> popełniane podczas używania strony biernej.",
    "rules": [
        {
            "label": "Akademicki",
            "color": "emerald",
            "text": "Strona bierna podkreśla <strong>obiektywizm</strong>:",
            "example": "The experiment was conducted..."
        },
        {
            "label": "Aktualności",
            "color": "blue",
            "text": "Strona bierna skupia się na <strong>wydarzeniu, a nie sprawcy</strong>:",
            "example": "Three people were injured."
        },
        {
            "label": "Błąd",
            "color": "rose",
            "text": "Zbędna strona bierna <strong>komplikuje</strong> tekst:",
            "example": "❌ The ball was kicked by him."
        }
    ]
}

{
    "title": "1. Gdzie strona bierna jest ODPOWIEDNIA",
    "sections": [
        {
            "label": "Styl akademicki i naukowy",
            "color": "emerald",
            "description": "W <strong>artykułach i opracowaniach naukowych</strong> strona bierna sprawia wrażenie obiektywizmu i dystansu.",
            "examples": [
                {
                    "en": "The experiment was conducted over six months.",
                    "ua": "Eksperyment prowadzono przez sześć miesięcy."
                },
                {
                    "en": "The data were collected from 500 participants.",
                    "ua": "Dane zebrano od 500 uczestników."
                },
                {
                    "en": "It has been demonstrated that...",
                    "ua": "Udowodniono, że..."
                },
                {
                    "en": "The results were analyzed using SPSS software.",
                    "ua": "Wyniki analizowano za pomocą programu SPSS."
                }
            ]
        },
        {
            "label": "Instrukcje i przepisy",
            "color": "sky",
            "description": "W <strong>instrukcjach</strong> strona bierna skupia się na procesie, a nie na wykonawcy.",
            "examples": [
                {
                    "en": "The mixture should be stirred for 5 minutes.",
                    "ua": "Całość należy mieszać przez 5 minut."
                },
                {
                    "en": "The device must be turned off before cleaning.",
                    "ua": "Przed czyszczeniem urządzenie należy wyłączyć."
                },
                {
                    "en": "First, the ingredients are combined.",
                    "ua": "Najpierw składniki się miesza."
                }
            ]
        },
        {
            "label": "Wiadomości i raporty",
            "color": "blue",
            "description": "W <strong>wiadomościach</strong> strona bierna koncentruje się na wydarzeniach i ofiarach, gdy sprawca jest nieznany lub nieistotny.",
            "examples": [
                {
                    "en": "Three people were injured in the accident.",
                    "ua": "W wypadku ranne zostały trzy osoby."
                },
                {
                    "en": "The bank was robbed yesterday.",
                    "ua": "Wczoraj okradziono bank."
                },
                {
                    "en": "A new law has been passed by Parliament.",
                    "ua": "Parlament przyjął nową ustawę."
                }
            ]
        },
        {
            "label": "Oficjalne dokumenty",
            "color": "amber",
            "description": "W <strong>korespondencji i dokumentach biznesowych</strong> strona bierna dodaje formalności.",
            "examples": [
                {
                    "en": "Your application has been received.",
                    "ua": "Twoje zgłoszenie zostało przyjęte."
                },
                {
                    "en": "Payment is required within 30 days.",
                    "ua": "Płatność jest wymagana w ciągu 30 dni."
                },
                {
                    "en": "Applicants will be notified by email.",
                    "ua": "Kandydaci zostaną powiadomieni e-mailem."
                }
            ]
        }
    ]
}

{
    "title": "2. Gdzie NAJLEPIEJ wykorzystać dany zasób",
    "sections": [
        {
            "label": "Kiedy wykonawca jest ważny",
            "color": "emerald",
            "description": "Jeśli <strong>kluczową informacją jest artysta</strong>, zasób brzmi bardziej naturalnie.",
            "examples": [
                {
                    "en": "❌ The goal was scored by Messi.",
                    "ua": "Bramkę zdobył Messi. (sztucznie)"
                },
                {
                    "en": "✅ Messi scored the goal.",
                    "ua": "Messi strzelił gola. (naturalnie)"
                },
                {
                    "en": "❌ The book was written by J.K. Rowling.",
                    "ua": "(jeśli chodzi o autora, atut jest lepszy)"
                },
                {
                    "en": "✅ J.K. Rowling wrote the book.",
                    "ua": "JK Rowling napisała książkę."
                }
            ]
        },
        {
            "label": "Język mówiony",
            "color": "sky",
            "description": "W <strong>codziennej komunikacji</strong> słowo aktywne brzmi prościej i bardziej naturalnie.",
            "examples": [
                {
                    "en": "❌ The cake was eaten by me.",
                    "ua": "Zjadłem ciasto. (niesamowicie)"
                },
                {
                    "en": "✅ I ate the cake.",
                    "ua": "Zjadłem ciasto. (naturalnie)"
                },
                {
                    "en": "❌ The door was opened by Tom.",
                    "ua": "Drzwi otworzył Tomek."
                },
                {
                    "en": "✅ Tom opened the door.",
                    "ua": "Tomek otworzył drzwi."
                }
            ]
        },
        {
            "label": "Krótsze zdania",
            "color": "amber",
            "description": "Aktywna część jest często <strong>krótsza i wyraźniejsza</strong>, zwłaszcza z frazą towarzyszącą.",
            "examples": [
                {
                    "en": "❌ Mistakes were made by me.",
                    "ua": "Błędy popełniłem ja. (8 słów)"
                },
                {
                    "en": "✅ I made mistakes.",
                    "ua": "Popełniłem błędy. (3 słowa)"
                },
                {
                    "en": "❌ The report was completed by the team.",
                    "ua": "Raport został uzupełniony przez zespół."
                },
                {
                    "en": "✅ The team completed the report.",
                    "ua": "Zespół uzupełnił raport."
                }
            ]
        },
        {
            "label": "Dynamiczne działania",
            "color": "rose",
            "description": "W przypadku <strong>szybkich, dynamicznych działań</strong> zasób lepiej przekazuje energię.",
            "examples": [
                {
                    "en": "❌ The ball was kicked by the player.",
                    "ua": "Piłka została uderzona przez zawodnika."
                },
                {
                    "en": "✅ The player kicked the ball.",
                    "ua": "Gracz uderzył piłkę."
                },
                {
                    "en": "❌ The car was driven by her.",
                    "ua": "Prowadziła samochód."
                },
                {
                    "en": "✅ She drove the car.",
                    "ua": "Prowadziła samochód."
                }
            ]
        }
    ]
}

{
    "title": "3. Błąd: „przez ludzi/kogoś” jest agentem zbędnym",
    "items": [
        {
            "label": "Błąd",
            "color": "rose",
            "title": "Zbędne „przez ludzi” lub „przez kogoś”.",
            "wrong": "English is spoken by people here.",
            "right": "✅ English is spoken here."
        },
        {
            "label": "Błąd",
            "color": "amber",
            "title": "Zbędne „przez nich” bez szczegółów.",
            "wrong": "The decision was made by them.",
            "right": "✅ The decision was made. (якщо \"вони\" неважливі)"
        },
        {
            "label": "Błąd",
            "color": "sky",
            "title": "Generalny wykonawca w stronie biernej.",
            "wrong": "It is believed by everybody that...",
            "right": "✅ It is believed that... / Everybody believes that..."
        }
    ]
}

{
    "title": "4. Błąd: błędny V3 (imiesłów przeszły)",
    "items": [
        {
            "label": "Niepoprawne czasowniki",
            "color": "rose",
            "title": "Zamieszanie z nieregularnymi kształtami.",
            "wrong": "The window was breaked. / was broke.",
            "right": "✅ The window was broken."
        },
        {
            "label": "Zakończenie - wyd",
            "color": "amber",
            "title": "Dodanie -ed do czasowników nieregularnych.",
            "wrong": "The letter was writed. / was sended.",
            "right": "✅ The letter was written. / was sent."
        },
        {
            "label": "V2 zamiast V3",
            "color": "sky",
            "title": "Używanie czasu Past Simple zamiast V3.",
            "wrong": "The book was wrote by her.",
            "right": "✅ The book was written by her."
        }
    ]
}

{
    "title": "5. Błąd: wyrównanie czasu",
    "items": [
        {
            "label": "Czas być + V3",
            "color": "rose",
            "title": "Niepoprawny czas formy pomocniczej be.",
            "wrong": "Yesterday, the report is written.",
            "right": "✅ Yesterday, the report was written."
        },
        {
            "label": "Teraźniejszość kontra przeszłość",
            "color": "amber",
            "title": "Pomieszanie teraźniejszości i przeszłości.",
            "wrong": "The project was completed tomorrow.",
            "right": "✅ The project will be completed tomorrow."
        },
        {
            "label": "Czasy doskonałe",
            "color": "sky",
            "title": "Skip był w czasie idealnym.",
            "wrong": "The work has done.",
            "right": "✅ The work has been done."
        }
    ]
}

{
    "title": "6. Błąd: nadmiarowy pasywny",
    "items": [
        {
            "label": "Nadmierna formalność",
            "color": "rose",
            "title": "Pasywny, gdzie aktywny jest lepszy.",
            "wrong": "The coffee was drunk by me this morning.",
            "right": "✅ I drank coffee this morning."
        },
        {
            "label": "Złożoność",
            "color": "amber",
            "title": "Złożoność prostych zdań.",
            "wrong": "A good time was had by all.",
            "right": "✅ Everyone had a good time."
        },
        {
            "label": "Utrata przejrzystości",
            "color": "sky",
            "title": "Kiedy zasób jest wyraźniejszy.",
            "wrong": "It was decided that the meeting would be postponed by the manager.",
            "right": "✅ The manager decided to postpone the meeting."
        }
    ]
}

{
    "title": "7. Kiedy jest to zobowiązanie, a kiedy składnik aktywów – szybkie sprawdzenie",
    "intro": "Tabela wyboru między aktywem a pasywem:",
    "rows": [
        {
            "en": "Виконавець невідомий",
            "ua": "→ PASYWNE",
            "note": "My car was stolen."
        },
        {
            "en": "Виконавець неважливий",
            "ua": "→ PASYWNE",
            "note": "English is spoken here."
        },
        {
            "en": "Виконавець важливий",
            "ua": "→ AKTYWNE",
            "note": "Messi scored the goal."
        },
        {
            "en": "Науковий/офіційний стиль",
            "ua": "→ PASYWNE",
            "note": "The data were analyzed."
        },
        {
            "en": "Розмовна мова",
            "ua": "→ AKTYWNE",
            "note": "I ate the cake."
        },
        {
            "en": "З \"by + очевидний agent\"",
            "ua": "→ Lepiej AKTYWNIE",
            "note": "Tom opened the door."
        }
    ],
    "warning": "📌 Zadaj sobie pytanie: <strong>Kto wykonuje akcję?</strong> Jeśli jest ona istotna – atut. Jeśli nie – biernie."
}

{
    "title": "8. Wskazówki dotyczące pisania akademickiego",
    "sections": [
        {
            "label": "Kiedy strona bierna jest odpowiednia",
            "color": "emerald",
            "description": "W <strong>pisarstwie akademickim</strong> strona bierna podkreśla proces i wynik, a nie autora.",
            "examples": [
                {
                    "en": "The samples were collected from three locations.",
                    "ua": "Próbki pobrano z trzech lokalizacji."
                },
                {
                    "en": "Statistical analysis was performed using SPSS.",
                    "ua": "Analizę statystyczną przeprowadzono za pomocą SPSS."
                },
                {
                    "en": "It was observed that temperature affects growth.",
                    "ua": "Zaobserwowano wpływ temperatury na wzrost."
                }
            ]
        },
        {
            "label": "Kiedy zasób jest lepszy",
            "color": "sky",
            "description": "Nawet w stylu akademickim <strong>aktywność</strong> jest czasem wyraźniejsza.",
            "examples": [
                {
                    "en": "Previous studies have shown that... (актив)",
                    "ua": "Poprzednie badania wykazały, że..."
                },
                {
                    "en": "We analyzed the data using... (актив)",
                    "ua": "Dane analizowaliśmy za pomocą..."
                },
                {
                    "en": "The authors conclude that... (актив)",
                    "ua": "Autorzy dochodzą do wniosku, że..."
                }
            ]
        },
        {
            "label": "Balansować",
            "color": "amber",
            "description": "<strong>Połącz</strong> elementy aktywne i pasywne, aby uzyskać różnorodność i przejrzystość.",
            "examples": [
                {
                    "en": "We collected samples (актив), which were then analyzed (пасив).",
                    "ua": "Pobraliśmy próbki, które następnie poddaliśmy analizie."
                },
                {
                    "en": "The experiment was designed (пасив) to test our hypothesis (актив).",
                    "ua": "Eksperyment miał na celu sprawdzenie naszej hipotezy."
                }
            ]
        }
    ]
}
